if (! function_exists('date_calculator')) {
    function date_calculator($operation, $date_a = null, $date_b = null, $interval = null, $output_format = null)
    {
        $allowed = ['diff','add','subtract','weekday','month_info','age','format'];
        if (!in_array($operation, $allowed)) {
            return json_encode(['error' => "Invalid operation. Must be one of: " . implode(', ', $allowed)]);
        }

        $result = [];

        try {
            switch ($operation) {
                case 'diff':
                    if (empty($date_a) || empty($date_b)) {
                        return json_encode(['error' => 'date_a and date_b required for diff']);
                    }
                    $d1 = new DateTime($date_a);
                    $d2 = new DateTime($date_b);
                    $interval = $d1->diff($d2);
                    $result = [
                        'date_a' => $d1->format('Y-m-d'),
                        'date_b' => $d2->format('Y-m-d'),
                        'days' => (int)$interval->format('%r%a'),
                        'years' => (int)$interval->format('%r%y'),
                        'months' => (int)$interval->format('%r%m'),
                        'total_days' => (int)$interval->format('%r%a'),
                        'invert' => $interval->invert ? 'date_b before date_a' : 'date_b after or same as date_a',
                        'human' => $interval->format('%y years, %m months, %d days'),
                    ];
                    break;

                case 'add':
                    if (empty($date_a) || empty($interval)) {
                        return json_encode(['error' => 'date_a and interval required for add']);
                    }
                    $d = new DateTime($date_a);
                    $d->add(DateInterval::createFromDateString($interval));
                    $result = [
                        'input_date' => $date_a,
                        'interval' => $interval,
                        'result_date' => $d->format('Y-m-d'),
                        'result_formatted' => $d->format('l, F jS, Y'),
                        'timestamp' => $d->getTimestamp(),
                    ];
                    break;

                case 'subtract':
                    if (empty($date_a) || empty($interval)) {
                        return json_encode(['error' => 'date_a and interval required for subtract']);
                    }
                    $d = new DateTime($date_a);
                    $d->sub(DateInterval::createFromDateString($interval));
                    $result = [
                        'input_date' => $date_a,
                        'interval' => $interval,
                        'result_date' => $d->format('Y-m-d'),
                        'result_formatted' => $d->format('l, F jS, Y'),
                        'timestamp' => $d->getTimestamp(),
                    ];
                    break;

                case 'weekday':
                    if (empty($date_a)) {
                        return json_encode(['error' => 'date_a required for weekday']);
                    }
                    $d = new DateTime($date_a);
                    $dayNumber = (int)$d->format('N'); // 1=Mon, 7=Sun
                    $days = ['', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
                    $shortDays = ['', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
                    $result = [
                        'date' => $d->format('Y-m-d'),
                        'day_of_week' => $days[$dayNumber],
                        'day_short' => $shortDays[$dayNumber],
                        'day_number' => $dayNumber,
                        'is_weekend' => $dayNumber >= 6,
                        'day_of_year' => (int)$d->format('z') + 1,
                        'week_of_year' => (int)$d->format('W'),
                    ];
                    break;

                case 'month_info':
                    if (empty($date_a)) {
                        return json_encode(['error' => 'date_a required for month_info']);
                    }
                    $d = new DateTime($date_a);
                    $year = (int)$d->format('Y');
                    $month = (int)$d->format('m');
                    $start = new DateTime("{$year}-{$month}-01");
                    $end = new DateTime("{$year}-{$month}-" . $d->format('t'));
                    $result = [
                        'month' => $d->format('F Y'),
                        'year' => $year,
                        'month_number' => $month,
                        'days_in_month' => (int)$d->format('t'),
                        'start_date' => $start->format('Y-m-d'),
                        'start_weekday' => $start->format('l'),
                        'end_date' => $end->format('Y-m-d'),
                        'end_weekday' => $end->format('l'),
                        'quarter' => ceil($month / 3),
                    ];
                    break;

                case 'age':
                    if (empty($date_a) || empty($date_b)) {
                        return json_encode(['error' => 'date_a (birth) and date_b (as_of) required for age']);
                    }
                    $birth = new DateTime($date_a);
                    $asOf = new DateTime($date_b);
                    $interval = $birth->diff($asOf);
                    $result = [
                        'birth_date' => $birth->format('Y-m-d'),
                        'as_of' => $asOf->format('Y-m-d'),
                        'age_years' => (int)$interval->format('%y'),
                        'age_months' => (int)$interval->format('%y') * 12 + (int)$interval->format('%m'),
                        'age_days' => (int)$interval->format('%a'),
                        'human' => $interval->format('%y years, %m months, %d days'),
                    ];
                    break;

                case 'format':
                    if (empty($date_a)) {
                        return json_encode(['error' => 'date_a required for format']);
                    }
                    $fmt = $output_format ?? 'Y-m-d';
                    $d = new DateTime($date_a);
                    $result = [
                        'input_date' => $date_a,
                        'output_format' => $fmt,
                        'formatted' => $d->format($fmt),
                        'iso_8601' => $d->format('c'),
                        'timestamp' => $d->getTimestamp(),
                    ];
                    break;
            }

            return json_encode(['operation' => $operation, 'result' => $result]);

        } catch (Exception $e) {
            return json_encode(['error' => 'Date error: ' . $e->getMessage()]);
        }
    }
